let actions={};
let formHandlers={};
let globalHandlersRegistered=false;
function missingAction(actionName){
  console.warn(`[Valora Pulse] Ação não registrada: ${actionName}`);
  toast('Esta ação ainda não está disponível neste ambiente.','warn');
}
function missingFormHandler(formName){
  console.warn(`[Valora Pulse] Formulário não registrado: ${formName}`);
  toast('Este formulário ainda não está disponível.','warn');
}
function handleDocumentClick(e){
  const el=e.target.closest('[data-action]'); if(!el)return;
  const actionName=el.dataset.action;
  const action=actions[actionName];
  e.preventDefault();
  if(typeof action!=='function')return missingAction(actionName);
  return run(`a ação “${actionName}”`,action,el,e);
}
function handleDocumentChange(e){
  const el=e.target.closest('[data-change]');if(!el)return;
  const change=changes[el.dataset.change];if(change)run(`a alteração “${el.dataset.change}”`,change,el,e);
}
function handleDocumentInput(e){
  const el=e.target.closest('[data-input]');if(!el)return;
  const change=inputs[el.dataset.input];if(change)run(`a edição “${el.dataset.input}”`,change,el,e);
}
function handleDocumentSubmit(e){
  const form=e.target.closest('form[data-form]');if(!form)return;
  e.preventDefault();
  const formName=form.dataset.form;
  const handler=formHandlers[formName];
  if(typeof handler!=='function')return missingFormHandler(formName);
  return run(`o envio de “${formName}”`,handler,form,e);
}
function handleDocumentKeydown(e){
  if(e.key==='Escape'){
    if($('#confirmLayer')?.classList.contains('open'))closeConfirm();
    else if($('#modalLayer')?.classList.contains('open'))closeModal();
    else toggleBot(false);
  }
}
function registerGlobalHandlers(){
  if(globalHandlersRegistered)return;
  document.addEventListener('click',handleDocumentClick);
  document.addEventListener('change',handleDocumentChange);
  document.addEventListener('input',handleDocumentInput);
  document.addEventListener('submit',handleDocumentSubmit);
  document.addEventListener('keydown',handleDocumentKeydown);
  globalHandlersRegistered=true;
}
function bootstrapApp(){
  actions=createActions();
  formHandlers=createFormHandlers();
  registerGlobalHandlers();
  run('a inicialização',init);
}

function legacyTraceEnabled(){return window.ValoraConfig?.observability?.legacyTraceEnabled===true;}
function safeRun(label,category,action,fn,options={}){
  try{
    if(legacyTraceEnabled())window.ValoraLogger?.debug({category,action,message:`Iniciando: ${label}`,metadata:options.metadata,user:currentUser?.()});
    const result=fn();
    if(legacyTraceEnabled())window.ValoraLogger?.info({category,action,message:`Concluído: ${label}`,metadata:options.metadata,user:currentUser?.()});
    return result;
  }catch(err){
    window.ValoraLogger?.error({category,action,message:`Erro em: ${label}`,error:err,metadata:options.metadata,user:currentUser?.()});
    handleError(label,err);
    return options.fallback;
  }
}
async function safeRunAsync(label,category,action,fn,options={}){
  try{
    if(legacyTraceEnabled())window.ValoraLogger?.debug({category,action,message:`Iniciando: ${label}`,metadata:options.metadata,user:currentUser?.()});
    const result=await fn();
    if(legacyTraceEnabled())window.ValoraLogger?.info({category,action,message:`Concluído: ${label}`,metadata:options.metadata,user:currentUser?.()});
    return result;
  }catch(err){
    window.ValoraLogger?.error({category,action,message:`Erro em: ${label}`,error:err,metadata:options.metadata,user:currentUser?.()});
    handleError(label,err);
    return options.fallback;
  }
}
function run(label,fn,...args){return safeRun(label,'system','legacy_run',()=>{const result=fn(...args);if(result&&typeof result.then==='function') result.catch(err=>handleError(label,err));return result;});}
function handleError(label,err){
  if(window.ValoraConfig?.observability?.consoleEnabled===true)console.error(`[Valora Pulse] ${label}`,err);
  try{window.ValoraLogger?.error({category:'system',action:'frontend_error',message:`Não foi possível concluir ${label}.`,error:err,route:currentRoute,user:currentUser?.()});}catch(_){ }
  if(label==='a inicialização')renderFatalStartupError(err);
  toast(`Não foi possível concluir ${label}. ${err?.message||err}`,'error');
  try{audit('Erro tratado','sistema','',`${label}: ${err?.message||err}`);}catch(_){ }
}
function renderFatalStartupError(error){
  const app=document.getElementById('app');
  if(!app)return;
  const isLocalMode=['localhost','127.0.0.1',''].includes(location.hostname)||APP_CONFIG.STORAGE_MODE==='local';
  const resetButton=isLocalMode?'<button class="btn btn-secondary" id="startupResetBtn" type="button">Recriar base local</button>':'';
  app.innerHTML=`<section class="section"><div class="container"><div class="card startup-error"><span class="badge danger">Falha na inicialização</span><h1>Não foi possível carregar o Valora Pulse™</h1><p>Atualize a página. Se o problema continuar, contate o suporte.</p><div class="confirm-actions"><button class="btn btn-primary" id="startupRetryBtn" type="button">Tentar novamente</button>${resetButton}</div>${isLocalMode?'<pre class="debug-box"></pre>':''}</div></div></section>`;
  const debug=app.querySelector('.debug-box');
  if(debug)debug.textContent=error?.stack||error?.message||String(error);
  app.querySelector('#startupRetryBtn')?.addEventListener('click',()=>location.reload());
  app.querySelector('#startupResetBtn')?.addEventListener('click',()=>{try{localStorage.removeItem(STORE_KEY);}catch(_){ } location.reload();});
}

window.addEventListener('error',e=>{window.ValoraLogger?.critical({category:'system',action:'global_error',message:'Erro global capturado.',error:e.error||new Error(e.message),route:currentRoute,user:currentUser?.()});handleError('a operação',e.error||new Error(e.message));});
window.addEventListener('unhandledrejection',e=>{if(isExternalBrowserNoise(e))return;window.ValoraLogger?.critical({category:'system',action:'unhandled_rejection',message:'Promise rejeitada sem tratamento.',error:e.reason||new Error('Falha desconhecida'),route:currentRoute,user:currentUser?.()});handleError('a operação assíncrona',e.reason||new Error('Falha desconhecida'));});
