function publicJourneyContext(){const u=new URL(location.href),sid=u.searchParams.get('survey'),rid=u.searchParams.get('result'),orgSlug=u.searchParams.get('org');const s=sid?state.surveys.find(x=>x.id===sid):rid?state.surveys.find(x=>x.id===state.responses.find(r=>r.id===rid)?.surveyId):null;const company=findOrganizationBySlug(orgSlug)||companyById(s?.companyId)||null;return {survey:s,company,companyName:company?.publicName||company?.name||companyName(s?.companyId)||'Valora Group'};}
function isDemoCompany(company){const name=String(company?.name||company?.publicName||'').trim().toLowerCase();const slug=String(company?.slug||'').trim().toLowerCase();return company?.id==='org_demo'||slug==='empresa-exemplo'||name==='empresa exemplo'||name==='empresa demonstração'||name==='empresa demonstracao';}
function shouldShowPublicCompanyChip(company){return !!company&&!isDemoCompany(company);}
function publicCompanyDisplay(company,fallback='Valora Group'){return isDemoCompany(company)?'Pesquisa demonstrativa Valora':(company?.publicName||company?.name||fallback);}
function sanitizePublicUrlForLog(link){try{const u=new URL(link,location.href);u.searchParams.delete('token');return u.toString();}catch(_){return '';}}
function isPublicSurveyUrl(link){try{const u=new URL(link,location.href);return !!(u.searchParams.get('survey')&&u.searchParams.get('token'));}catch(_){return String(link||'').includes('?survey=')&&String(link||'').includes('token=');}}
function publicWhatsappUrl(ctx=publicJourneyContext()){const raw=onlyDigits(ctx.company?.settings?.whatsapp||ctx.company?.phone||state.settings.whatsappNumber);if(!raw)return '';const msg=`Olá! Preciso de ajuda para responder a pesquisa ${ctx.survey?.title||'Valora Pulse'} da ${publicCompanyDisplay(ctx.company,ctx.companyName)}.`;return `https://wa.me/${raw}?text=${encodeURIComponent(msg)}`;}
function renderPublicSurveyShell(context={}){const ctx={...publicJourneyContext(),...context};const wa=publicWhatsappUrl(ctx);const chip=shouldShowPublicCompanyChip(ctx.company)?`<div class="public-company-chip" aria-label="Empresa da pesquisa">${esc(ctx.company.publicName||ctx.company.name)}</div>`:'';$('#topbar').innerHTML=`<div class="container public-survey-header"><div class="public-survey-brand"><img src="${LOGO_SYMBOL}" alt="Símbolo Valora Group"><div><b>Valora Group™</b><span>Pesquisa segura</span></div></div>${chip}<nav class="public-survey-actions" aria-label="Ajuda e suporte da pesquisa"><button class="public-home-button" data-action="goHomeFromPublicSurvey" aria-label="Voltar para Home">← <span>Home</span></button><a class="public-help-button" href="index.html#public-help" target="_blank" rel="noopener" data-action="publicHelpClick" aria-label="Abrir ajuda da pesquisa pública em nova aba"><span class="help-mark" aria-hidden="true">?</span><span>Ajuda</span></a><button class="public-bot-button" data-action="toggleBot" aria-label="Abrir ValoraBot" title="ValoraBot"><span class="icon-valora-bot" aria-hidden="true">💬</span></button>${wa?`<a class="public-whatsapp-button" href="${wa}" target="_blank" rel="noopener" data-action="publicWhatsappClick" aria-label="Falar no WhatsApp" title="Falar no WhatsApp"><span class="icon-whatsapp" aria-hidden="true">WA</span></a>`:''}</nav></div>`;$('#footer').innerHTML=`<div class="container public-footer"><small>Link seguro protegido pela Valora Group™${ctx.company?.brand?.showPoweredByValora!==false?' • Powered by Valora Group':''}</small></div>`;renderFloating();}
function renderFloating(){
  const publicPage=isPublicJourneyPage(),ctx=publicJourneyContext();
  const waUrl=publicPage?publicWhatsappUrl(ctx):(state.settings.whatsappEnabled&&onlyDigits(state.settings.whatsappNumber)?`https://wa.me/${onlyDigits(state.settings.whatsappNumber)}?text=${encodeURIComponent('Olá! Quero conhecer o Valora Pulse™.')}`:'');
  const w=waUrl?`<a class="float-btn float-whatsapp ${publicPage?'public-whatsapp-button':''}" href="${waUrl}" target="_blank" rel="noopener" data-action="${publicPage?'publicWhatsappClick':''}" aria-label="Falar no WhatsApp" title="Falar no WhatsApp"><span class="icon-whatsapp" aria-hidden="true">WA</span></a>`:'';
  const b=shouldShowValoraBot()?`<button class="float-btn float-help ${publicPage?'public-bot-button':''}" data-action="toggleBot" aria-label="Abrir ValoraBot" title="ValoraBot"><span class="icon-valora-bot" aria-hidden="true">💬</span></button>`:'';
  $('#floatActions').classList.toggle('public-floating-actions',publicPage);$('#floatActions').innerHTML=w+b;renderBot();
}
function shouldShowValoraBot(){const u=currentUser();if(isPublicJourneyPage())return true;if(!u)return true;return moduleEnabled('valorabot')||getRoleDefinition(u.role)?.scope==='valora';}
function botGreeting(){const ctx=window.ValoraChatbot?.getChatContext?.()||{};if(ctx.isPublicSurvey||ctx.isPublicResult||['participante','convidado_externo'].includes(ctx.role))return 'Olá! Posso te ajudar a responder a pesquisa, entender seu resultado ou baixar seu certificado.';if(['empresa_admin','gestor_pesquisa'].includes(ctx.role))return 'Olá! Posso ajudar com pesquisas, respostas, relatórios, usuários e plano de ação.';if(['admin_valora','consultor_valora'].includes(ctx.role))return 'Olá! Posso apoiar na administração da plataforma, clientes, planos, formulários, importação e operação publicada.';if(!ctx.isLoggedIn)return 'Olá! Posso te ajudar a entender os planos, o Valora Insight™ ou como iniciar um diagnóstico.';return 'Olá, eu sou o ValoraBot. Posso te ajudar a entender o diagnóstico, os planos, sua pesquisa, seus resultados ou direcionar você para atendimento humano.';}
function renderBot(){
  const open=$('#botPanel')?.classList.contains('open');
  const suggestions=window.ValoraChatbot?.getSuggestedQuestions?.()||['Como respondo a pesquisa?','Meus dados estão seguros?','Como falar com suporte?'];
  $('#botPanel').innerHTML=`<div class="bot-head"><div class="bot-title"><span class="bot-avatar">V</span><div><b>ValoraBot</b><small>Assistente do Valora Pulse™</small></div></div><button class="btn btn-mini btn-secondary" data-action="toggleBot">Fechar</button></div><div class="bot-messages" id="botMessages"><div class="bot-msg"><b>ValoraBot</b><br>${esc(botGreeting())}<small>${new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})}</small></div><div class="bot-quick">${suggestions.map(q=>`<button class="btn btn-soft btn-mini" data-action="botQuick" data-text="${esc(q)}">${esc(q)}</button>`).join('')}<button class="btn btn-secondary btn-mini" data-action="botAction" data-type="support" data-value="human">Falar com atendente</button></div></div><form class="bot-input" data-form="bot"><input name="message" aria-label="Mensagem para o ValoraBot" placeholder="Digite sua dúvida"><button class="btn btn-primary btn-mini">Enviar</button></form>`;
  $('#botPanel').classList.toggle('open',open);$('#botPanel').setAttribute('aria-hidden',open?'false':'true');
}

function resolveFeaturedFreeSurvey(store=state){
  const settings=store?.settings||{};
  const surveys=Array.isArray(store?.surveys)?store.surveys:[];
  const isUsable=survey=>survey&&survey.status==='active'&&survey.visibleOnHome!==false&&(!survey.expiresAt||new Date(survey.expiresAt)>new Date());
  const featured=surveys.find(survey=>survey.id===settings.featuredSurveyId&&isUsable(survey));
  if(featured)return featured;
  return surveys.find(survey=>isUsable(survey)&&(survey.isFree===true||survey.isFeatured===true||survey.planId==='free'))||null;
}
function resolveFeaturedSurveyLink(survey){
  if(!survey)return '';
  if(survey.publicUrl)return survey.publicUrl;
  if(survey.publicLink)return survey.publicLink;
  if(typeof buildSurveyLink==='function')return buildSurveyLink(survey);
  return buildPublicSurveyUrl(survey);
}
function getFeaturedFreeSurvey(){return resolveFeaturedFreeSurvey(state);}
function buildPublicSurveyUrl(survey){
  if(!survey)return '#plans';
  if(survey.publicLink)return survey.publicLink;
  if(survey.link)return survey.link;
  const token=survey.token||survey.publicToken||survey.accessToken||'';
  const org=companyById(survey.companyId)?.slug||'';
  if(!token)return '#plans';
  return `index.html?survey=${encodeURIComponent(survey.id)}&token=${encodeURIComponent(token)}${org?`&org=${encodeURIComponent(org)}`:''}`;
}
