function getPublicPricingPlans(){
  const plans=(state.plans||[])
    .filter(p=>p.visibleOnPublicPricing!==false&&!p.internalOnly)
    .sort((a,b)=>(a.displayOrder||99)-(b.displayOrder||99));
  const officialIds=['free','essential','professional','corporate','enterprise'];
  return officialIds.every(id=>plans.some(p=>p.id===id))&&plans.length===5?plans:officialPublicPricingPlans();
}
function publicPlans(){return getPublicPricingPlans();}
