const calculateResult=calculateSurveyResult;


const VALORA_INSIGHT_DIMENSIONS=['Cultura e Propósito','Gestão e Governança','Liderança','Pessoas e Talentos','Resultados e Crescimento'];
function isValoraInsightForm(form={}){return /Valora Insight/i.test(String(form?.name||form?.id||''));}
function getValoraMaturityLevel(totalScore){const n=Number(totalScore||0);if(n<=55)return{id:'critical',label:'Crítico',icon:'🔴',color:'#b5262b'};if(n<=85)return{id:'structuring',label:'Em estruturação',icon:'🟡',color:'#c47b00'};if(n<=110)return{id:'structured',label:'Estruturada',icon:'🟢',color:'#08764e'};return{id:'high_maturity',label:'Alta maturidade',icon:'🔵',color:'#0f5265'};}
function valoraDimensionLevel(score){const n=Number(score||0);if(n<=11)return{id:'critical',label:'Crítica',icon:'🔴',color:'#b5262b'};if(n<=17)return{id:'attention',label:'Em estruturação',icon:'🟡',color:'#c47b00'};if(n<=22)return{id:'consistent',label:'Estruturada',icon:'🟢',color:'#08764e'};return{id:'advanced',label:'Alta maturidade',icon:'🔵',color:'#0f5265'};}
function renderRadarBar(score,max=25){const blocks=10,safeMax=Number(max)>0?Number(max):25,safeScore=Number.isFinite(Number(score))?Number(score):0,filled=clamp(Math.round((clamp(safeScore,0,safeMax)/safeMax)*blocks),0,blocks);return '█'.repeat(filled)+'░'.repeat(blocks-filled);}
function valoraDimId(name){const n=String(name||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();if(n.includes('cultura'))return'cultura';if(n.includes('govern'))return'governanca';if(n.includes('lider'))return'lideranca';if(n.includes('pessoas')||n.includes('talentos'))return'talentos';if(n.includes('result')||n.includes('crescimento'))return'resultados';if(n.includes('esg')||n.includes('sustent'))return'esg';return n.replace(/[^a-z0-9]+/g,'_');}
function isEsgDimensionName(name){return /\bESG\b|Sustentabilidade/i.test(String(name||''));}
function normalizeLegacyValoraInsightResponse(response={},form={}){const originalMax=Number(response.maxScore??response.totalMax??0);const legacy=originalMax>125||Object.keys(response.byDimension||{}).some(isEsgDimensionName)?{rawScore:response.rawScore,maxScore:originalMax,byDimension:deepClone(response.byDimension||{})}:response.legacyScore;return {...response,legacyScore:legacy};}
function calculateValoraInsightResult(response={},form={}){const source=normalizeLegacyValoraInsightResponse(response,form),by=source.byDimension||{};const calculatedDims=Array.isArray(source.dimensions)?source.dimensions:[];const persistedDims=Array.isArray(source.valoraInsight?.dimensionScores)?source.valoraInsight.dimensionScores:[];const dims=VALORA_INSIGHT_DIMENSIONS.map(name=>{const found=Object.entries(by).find(([k])=>valoraDimId(k)===valoraDimId(name));const calculated=calculatedDims.find(d=>valoraDimId(d.id||d.name)===valoraDimId(name));const persisted=persistedDims.find(d=>valoraDimId(d.id||d.name)===valoraDimId(name));let score=found?Number(found[1].rawScore??0):Number(calculated?.score??persisted?.score??0);if(!found&&!calculated&&!persisted&&form?.questions&&source.answers){score=form.questions.filter(q=>valoraDimId(q.dimensionName||formDimensionName(form,q.dimensionId))===valoraDimId(name)).reduce((sum,q)=>sum+Number(source.answers?.[q.id]||0),0);}score=clamp(Math.round(score),0,25);const level=valoraDimensionLevel(score);return{id:valoraDimId(name),name,score,maxScore:25,percentage:score/25*100,level,insight:dimensionStrategicReading(name,score)}});const totalScore=dims.reduce((s,d)=>s+d.score,0),m=getValoraMaturityLevel(totalScore);const sorted=[...dims].sort((a,b)=>a.score-b.score);const weakestDimension=sorted[0]||null,strongestDimension=sorted.at(-1)||null;return{totalScore,maxScore:125,percentage:totalScore/125*100,maturityLevel:m,maturityLabel:m.label,maturityColor:m.color,dimensions:dims,weakestDimension,strongestDimension,structuralBlocker:weakestDimension?.name||'',radar:dims.map(d=>`${d.name}: ${renderRadarBar(d.score)} ${d.score}/25`),createdAt:source.createdAt||source.valoraInsight?.generatedAt||nowIso()};}
function dimensionStrategicReading(name,score){const low=score<=11,mid=score<=17,ok=score<=22;if(/Cultura/.test(name))return low?'A cultura ainda depende mais de discurso do que de comportamento repetido.':mid?'Há sinais de alinhamento, mas a prática ainda oscila entre áreas e lideranças.':ok?'A cultura já cria orientação, mas precisa virar critério consistente de decisão.':'A cultura opera como ativo de coordenação e reduz ruído na execução.';if(/Governança/.test(name))return low?'A gestão depende de pessoas-chave, com decisão pouco previsível.':mid?'A governança existe em partes, mas ainda não sustenta rotina decisória madura.':ok?'Há base de decisão e acompanhamento, com pontos a consolidar para escalar.':'A gestão opera com clareza, indicadores e menor dependência individual.';if(/Liderança/.test(name))return low?'A liderança tende a atuar de forma reativa e centralizada.':mid?'As lideranças direcionam, mas ainda alternam autonomia e controle excessivo.':ok?'A liderança já sustenta boa parte da execução, mas precisa ampliar maturidade decisória.':'As lideranças funcionam como sistema, não apenas como esforço individual.';if(/Pessoas/.test(name))return low?'A equipe depende de esforço individual, com baixo desenvolvimento estruturado.':mid?'Há talentos relevantes, mas retenção e desenvolvimento ainda não são sistema.':ok?'Pessoas e talentos já sustentam a operação, com oportunidades de fortalecer autonomia.':'A organização desenvolve, retém e distribui capacidade com consistência.';return low?'O crescimento é mais reativo do que controlado e tende a gerar desgaste.':mid?'Há resultado, mas a previsibilidade ainda é limitada por instabilidade operacional.':ok?'O crescimento tem base funcional, mas precisa ampliar controle e dados.':'Resultados são acompanhados com previsibilidade e capacidade de sustentação.';}
function strategicTruthFor(result){const w=result.weakestDimension?.name||'',gov=result.dimensions.find(d=>d.id==='governanca')?.score||0,lead=result.dimensions.find(d=>d.id==='lideranca')?.score||0,res=result.dimensions.find(d=>d.id==='resultados')?.score||0,spread=(result.strongestDimension?.score||0)-(result.weakestDimension?.score||0);if(gov<=13)return'O que limita sua empresa não é o mercado. É a forma como ela decide.';if(lead<=13)return'Sua empresa não está travada. Ela está dependente demais de poucas lideranças.';if(/Pessoas/.test(w))return'O crescimento da empresa ainda depende mais de esforço individual do que de um sistema de desenvolvimento.';if(res<=13)return'Sua empresa não tem apenas um desafio de resultado. Ela tem um desafio de sustentação.';if(/Cultura/.test(w))return'A cultura ainda não virou sistema. Ela depende mais do discurso do que da prática diária.';if(spread>=9)return'O risco central não é a falta de força. É o desequilíbrio entre áreas que deveriam evoluir juntas.';return'A maturidade atual já revela valor, mas também mostra exatamente onde o crescimento começa a ficar caro.';}
function generateValoraInsightDevolutiva(result,form,response){const r=calculateValoraInsightResult(result||response||{},form||{}),truth=strategicTruthFor(r),w=r.weakestDimension,s=r.strongestDimension,nextPriority={governanca:'Governança → estrutura de decisão, critérios claros e rotina de acompanhamento antes de acelerar novas iniciativas.',talentos:'Pessoas → desenvolvimento, autonomia e retenção para reduzir dependência de esforço individual.',lideranca:'Liderança → maturidade decisória, delegação real e menor centralização em poucas pessoas.',resultados:'Resultados → gestão por dados, previsibilidade e sustentação do crescimento sem desgaste excessivo.',cultura:'Cultura → alinhamento comportamental real entre discurso, decisão e prática diária.'}[w?.id]||'Priorizar o bloqueador estrutural indicado pelo diagnóstico.';const levelText={critical:'A empresa opera em estágio crítico: a execução depende de esforço individual, decisões reativas e baixa previsibilidade.',structuring:'Sua empresa já apresenta sinais de organização, mas ainda não opera com maturidade suficiente para sustentar crescimento com previsibilidade.',structured:'A empresa possui estrutura funcional, mas ainda precisa reduzir pontos de dependência para crescer com menos desgaste.',high_maturity:'A empresa opera com alta maturidade, mas deve proteger coerência, velocidade decisória e evolução contínua.'}[r.maturityLevel.id];const dimensionDiagnosis=r.dimensions.map(d=>({name:d.name,score:d.score,maxScore:25,level:d.level,analysis:d.insight,consequence:d.score<=11?'Consequência prática: a dimensão trava as demais e aumenta dependência da liderança.':d.score<=17?'Consequência prática: a operação funciona, mas com instabilidade e retrabalho.':d.score<=22?'Consequência prática: há base de escala, desde que o padrão seja consolidado.':'Consequência prática: esta dimensão ajuda a sustentar crescimento com menor desgaste.'}));return{title:'VALORA INSIGHT™ — DEVOLUTIVA ESTRATÉGICA',subtitle:'Análise executiva direta da maturidade organizacional.',totalScoreText:`Pontuação total: ${r.totalScore} / 125`,maturityLevel:r.maturityLevel,executiveSummary:`${r.totalScore}/125 — ${r.maturityLevel.icon} ${r.maturityLevel.label}. ${levelText} O limite invisível deste estágio aparece em ${w?.name||'—'}, porque essa dimensão condiciona velocidade, consistência e qualidade das decisões.`,directReading:`Os dados indicam nível de previsibilidade ${r.totalScore<=55?'baixo':r.totalScore<=85?'parcial':r.totalScore<=110?'funcional':'alto'}, maturidade de decisão ${r.dimensions.find(d=>d.id==='governanca')?.score<=17?'ainda dependente de poucos critérios':'mais estruturada'} e crescimento ${r.dimensions.find(d=>d.id==='resultados')?.score<=17?'com risco de desgaste':'com melhor sustentação'}. A operação deve tratar ${w?.name||'a dimensão crítica'} como gargalo, não como detalhe.`,dimensionDiagnosis,radarText:r.radar.join('\n'),radarExplanation:`O radar mostra ${w?.name||'—'} como principal bloqueador estrutural e ${s?.name||'—'} como ponto de sustentação. O desequilíbrio entre dimensões define onde a empresa perde energia organizacional.`,benchmarking:`Benchmarking qualitativo: frente a empresas iniciantes, a leitura mostra ${r.totalScore>55?'mais repertório estrutural':'fragilidades típicas de fundação organizacional'}. Frente a empresas em crescimento, ${w?.score<=17?'a empresa ainda fica abaixo no bloqueador central '+w.name:'a empresa se aproxima, mas precisa reduzir variações entre áreas'}. Frente a empresas maduras, o avanço depende de governança, liderança autônoma, dados e rotinas que não dependam de heroísmo individual.`,strategicTruth:truth,riskIfNothingChanges:`Se nada mudar nos próximos 6 a 18 meses, a tendência é aumento de dependência de pessoas-chave, lentidão decisória, perda de margem por retrabalho e crescimento com desgaste. Não é uma previsão dramática; é a consequência natural de manter o mesmo padrão de maturidade.`,nextLevelGuidance:`Próximo nível prioritário: ${nextPriority} Direção completa: Cultura → alinhamento comportamental real; Governança → estrutura de decisão; Liderança → autonomia e maturidade; Pessoas → desenvolvimento e retenção; Resultados → gestão por dados e previsibilidade.`,transitionToSolution:'O diagnóstico Valora Insight™ marca um ponto de virada: não se trata mais de entender o cenário, mas de atuar sobre as causas que estão limitando o crescimento da empresa. Fale com o Valora Group para estruturar seu próximo nível de maturidade. +55 91 99254-5353',finalPrinciple:'Empresas não evoluem quando entendem o diagnóstico.\nElas evoluem quando aceitam a verdade que ele revela.',result:r};}
function valoraInsightHtml(insight){const d=insight;return `<section class="insight-report"><div class="insight-section"><h3>Enquadramento geral sem adoçamento</h3><p>${esc(d.totalScoreText)}. ${esc(d.executiveSummary)}</p></div><div class="insight-hero"><div><span class="badge dark">${esc(d.title)}</span><h2>${esc(d.subtitle)}</h2><p>${esc(d.executiveSummary)}</p></div><div class="insight-score-card"><strong>${esc(d.result.totalScore)}</strong><span>/125</span><b class="insight-level-badge" style="background:${esc(d.maturityLevel.color)}">${esc(d.maturityLevel.icon)} ${esc(d.maturityLevel.label)}</b></div></div><div class="insight-section"><h3>Leitura executiva da realidade</h3><p>${esc(d.directReading)}</p></div><div class="insight-section"><h3>Diagnóstico por dimensão</h3><div class="insight-dimensions">${d.dimensionDiagnosis.map(x=>`<article><h4>${esc(x.name)}</h4><b style="color:${esc(x.level.color)}">${esc(x.level.icon)} ${x.score}/25 — ${esc(x.level.label)}</b><p>${esc(x.analysis)}</p><p><strong>${esc(x.consequence)}</strong></p></article>`).join('')}</div></div><div class="insight-section insight-radar"><h3>Radar Organizacional</h3><pre>${esc(d.radarText)}</pre><p>${esc(d.radarExplanation)}</p></div><div class="insight-section"><h3>Benchmarking qualitativo</h3><p>${esc(d.benchmarking)}</p></div><div class="insight-truth"><h3>Verdade estratégica central</h3><p>${esc(d.strategicTruth)}</p></div><div class="insight-risk"><h3>Risco se nada mudar</h3><p>${esc(d.riskIfNothingChanges)}</p></div><div class="insight-next-level"><h3>Próximo nível de evolução</h3><p>${esc(d.nextLevelGuidance)}</p></div><div class="insight-cta"><p>${esc(d.transitionToSolution)}</p><b class="preline">${esc(d.finalPrinciple)}</b></div></section>`;}
