function getCertificateScore(response={}){const raw=Number(response.rawScore??response.totalScore),max=Number(response.maxScore??response.totalMax);let percentage=Number(response.percentage),normalized5=Number(response.normalized5??response.average);if(Number.isFinite(raw)&&Number.isFinite(max)&&max>0){percentage=clamp((raw/max)*100,0,100);normalized5=clamp(percentage/20,0,5);}else if(Number.isFinite(normalized5)){normalized5=clamp(normalized5,0,5);percentage=clamp(normalized5*20,0,100);}else if(Number.isFinite(percentage)){percentage=clamp(percentage,0,100);normalized5=clamp(percentage/20,0,5);}const hasReliableScore=Number.isFinite(normalized5)&&Number.isFinite(percentage)&&(max>0||response.normalized5!==undefined||response.percentage!==undefined||response.average!==undefined);const band=response.band||response.level||{};const maturityLabel=safeText(band.label||response.maturityLabel||(hasReliableScore?dimensionRecommendation(normalized5):''),hasReliableScore?'Resultado registrado':'Participação confirmada');const maturityDescription=safeText(band.description||response.maturityDescription||(hasReliableScore?dimensionRecommendation(normalized5):''),'Participação registrada com sucesso.');return {hasReliableScore,normalized5:hasReliableScore?normalized5:0,percentage:hasReliableScore?percentage:0,scoreValue:hasReliableScore?`${formatDecimal(normalized5,1)} / 5`:'',scoreShortLabel:hasReliableScore?`${formatDecimal(normalized5,1)} / 5 • ${formatDecimal(percentage,0)}%`:'Participação concluída',scoreLabel:hasReliableScore?`Índice de maturidade: ${formatDecimal(normalized5,1)} / 5 • Aproveitamento: ${formatDecimal(percentage,0)}%`:'Participação concluída',maturityLabel,maturityDescription,band};}
