function openSupportChat(){audit('Atendimento humano aberto','jornada_publica','','Solicitação de atendimento');const u=currentUser(),ctx=publicJourneyContext();const catOpts=(state.supportCategories||defaultSupportCategories()).map(c=>`<option value="${esc(c.id)}">${esc(c.label)}</option>`).join('');if(!u)return openModal('Falar com atendente',`<form data-form="publicSupport" class="grid"><div class="field"><label>Nome</label><input name="name" required></div><div class="field"><label>E-mail</label><input name="email" type="email" required></div><div class="field"><label>Categoria</label><select name="category">${catOpts}</select></div><div class="field"><label>Assunto</label><input name="subject" required></div><div class="field"><label>Mensagem</label><textarea name="message" required></textarea></div><button class="btn btn-primary">Abrir atendimento</button></form>`,'small');openModal('Novo atendimento',`<form data-form="loggedSupport" class="grid"><div class="page-help">Usaremos seu perfil (${esc(ROLE_LABELS[u.role]||u.role)}), e-mail e empresa automaticamente.</div><div class="field"><label>Categoria</label><select name="category">${catOpts}</select></div><div class="field"><label>Prioridade</label><select name="priority"><option value="low">Baixa</option><option value="medium" selected>Média</option><option value="high">Alta</option><option value="critical">Crítica</option></select></div><div class="field"><label>Assunto</label><input name="subject" required></div><div class="field"><label>Mensagem</label><textarea name="message" required></textarea></div><button class="btn btn-primary">Abrir atendimento</button></form>`,'small');}
function createSupportConversation(data0){state.supportTickets=state.supportTickets||state.supportConversations||[];state.supportMessages=state.supportMessages||[];const c=routeSupportTicket(normalizeSupportConversation(data0));state.supportTickets.push(c);state.supportConversations=state.supportTickets;window.ValoraLogger?.info({category:'support_chat',action:'ticket_created',message:'Ticket de suporte aberto.',companyId:c.companyId,metadata:{ticketId:c.id,origin:c.origin,category:c.category,priority:c.priority}});save();return c;}
function savePublicSupport(form){const fd=data(form),ctx=publicJourneyContext(),cat=supportCategory(fd.category);const c=createSupportConversation({requesterName:fd.name,requesterEmail:fd.email,requesterType:'public',origin:isPublicSurveyPage()?'public_survey':'portal',channel:'web',companyId:ctx.company?.id||'',companyName:ctx.companyName,category:fd.category,priority:cat?.defaultPriority||'medium',subject:fd.subject,description:fd.message,relatedEntity:isPublicSurveyPage()?'survey':'',relatedSurveyId:ctx.survey?.id||'',relatedRoute:location.hash||location.search});sendSupportMessage(c.id,fd.message,'requester');closeModal();renderSupportChat(c.id);toast('Atendimento aberto com sucesso. Um atendente responderá por aqui.','success');}
