function renderSupportList(rows){return `<div class="card table-wrap"><table class="table"><thead><tr><th>Ticket</th><th>Status</th><th>SLA</th><th>Prioridade</th><th>Categoria</th><th>Empresa</th><th>Solicitante</th><th>Assunto</th><th>Ações</th></tr></thead><tbody>${rows.slice().reverse().map(c=>`<tr><td>${esc(c.id)}</td><td>${esc(SUPPORT_STATUS_LABELS[c.status]||c.status)}</td><td>${esc(slaStatus(c))}</td><td>${esc(SUPPORT_PRIORITY_LABELS[c.priority]||c.priority)}</td><td>${esc(supportCategory(c.category)?.label||c.category)}</td><td>${esc(companyName(c.companyId)||'Valora')}</td><td>${esc(c.requesterName)}</td><td>${esc(c.subject)}</td><td><button class="btn btn-secondary btn-mini" data-action="openSupportConversation" data-id="${esc(c.id)}">Abrir</button></td></tr>`).join('')||'<tr><td colspan="9">Nenhum atendimento.</td></tr>'}</tbody></table></div>`;}
function filterSupport(){const st=$('#supportStatus')?.value,pr=$('#supportPriority')?.value,over=$('#supportOverdue')?.checked,u=currentUser();let rows=(state.supportTickets||state.supportConversations||[]).filter(c=>canSeeSupport(c,u));if(st)rows=rows.filter(c=>c.status===st);if(pr)rows=rows.filter(c=>c.priority===pr);if(over)rows=rows.filter(c=>slaStatus(c)==='vencido');const box=$('#supportList');if(box)box.innerHTML=renderSupportList(rows);enhanceResponsiveTables(box||document);}
