  const p={status:'active',maxEmployees:0,maxEmailsMonth:0,audience:'',commercialBadge:'',priceLabel:'',ctaLabel:'Escolher plano',features:[],enabledModules:null,internalNotes:'',allowReports:true,allowCertificates:true,allowEmailSending:true,allowValoraBot:false,allowExport:true,allowCustomQuestionnaires:true,allowGlobalTemplates:false,...(plan||{})};
